function buildS2306Xml(dto: S2306TsvContractChangeDto, ctx: BuilderContext): BuiltXml {
  validateRequired(dto, ['tenantId', 'sourceEventId', 'employerCnpj', 'kind', 'contractId', 'cpf', 'registration', 'changeDate']);
